&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&amp;nbsp;Justice M Sundar Sworn in as 10th Chief Justice of Manipur High Court.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;219&quot; data-start=&quot;101&quot;&gt;
	&lt;p data-end=&quot;219&quot; data-start=&quot;103&quot;&gt;&lt;strong data-end=&quot;123&quot; data-start=&quot;103&quot;&gt;Justice M Sundar&lt;/strong&gt; was sworn in as the &lt;strong data-end=&quot;192&quot; data-start=&quot;144&quot;&gt;10th Chief Justice of the Manipur High Court.&lt;/strong&gt;&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;329&quot; data-start=&quot;220&quot;&gt;
	&lt;p data-end=&quot;329&quot; data-start=&quot;222&quot;&gt;The oath was administered by &lt;strong data-end=&quot;289&quot; data-start=&quot;251&quot;&gt;Manipur Governor Ajay Kumar Bhalla&lt;/strong&gt; at &lt;strong data-end=&quot;320&quot; data-start=&quot;293&quot;&gt;Darbar Hall, Raj Bhavan&lt;/strong&gt;, Imphal.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;427&quot; data-start=&quot;330&quot;&gt;
	&lt;p data-end=&quot;427&quot; data-start=&quot;332&quot;&gt;Justice Sundar succeeds &lt;strong data-end=&quot;387&quot; data-start=&quot;356&quot;&gt;Justice Kempaiah Somashekar.&lt;/strong&gt;&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;502&quot; data-start=&quot;428&quot;&gt;
	&lt;p data-end=&quot;502&quot; data-start=&quot;430&quot;&gt;The&amp;nbsp;&lt;strong&gt;Supreme Court Collegium recommended him&lt;/strong&gt;&amp;nbsp;for this position.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;646&quot; data-start=&quot;503&quot;&gt;
	&lt;p data-end=&quot;646&quot; data-start=&quot;505&quot;&gt;&lt;strong data-end=&quot;524&quot; data-start=&quot;505&quot;&gt;Born in Chennai&lt;/strong&gt; on &lt;strong data-end=&quot;545&quot; data-start=&quot;528&quot;&gt;July 19, 1966&lt;/strong&gt;, Justice Sundar graduated from &lt;strong data-end=&quot;599&quot; data-start=&quot;577&quot;&gt;Madras Law College&lt;/strong&gt; and started his career as an advocate in 1989.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;806&quot; data-start=&quot;647&quot;&gt;
	&lt;p data-end=&quot;806&quot; data-start=&quot;649&quot;&gt;He was elevated as a &lt;strong data-end=&quot;689&quot; data-start=&quot;670&quot;&gt;permanent judge&lt;/strong&gt; of the &lt;strong data-end=&quot;718&quot; data-start=&quot;697&quot;&gt;Madras High Court&lt;/strong&gt; in &lt;strong data-end=&quot;738&quot; data-start=&quot;722&quot;&gt;October 2016&lt;/strong&gt; and served as the &lt;strong data-end=&quot;785&quot; data-start=&quot;757&quot;&gt;second senior-most judge&lt;/strong&gt; before his transfer.&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;न्यायमूर्ति केम्पैया सोमशेखर&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;न्यायमूर्ति एम सुंदर ने मणिपुर उच्च न्यायालय के 10वें मुख्य न्यायाधीश के रूप में शपथ ली।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;219&quot; data-start=&quot;101&quot;&gt;
	&lt;p data-end=&quot;219&quot; data-start=&quot;103&quot;&gt;&lt;strong data-end=&quot;123&quot; data-start=&quot;103&quot;&gt;न्यायमूर्ति एम सुंदर&lt;/strong&gt; को &lt;strong data-end=&quot;192&quot; data-start=&quot;144&quot;&gt;मणिपुर उच्च न्यायालय के 10वें मुख्य न्यायाधीश&lt;/strong&gt; के रूप में शपथ दिलाई गई।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;329&quot; data-start=&quot;220&quot;&gt;
	&lt;p data-end=&quot;329&quot; data-start=&quot;222&quot;&gt;शपथ &lt;strong data-end=&quot;289&quot; data-start=&quot;251&quot;&gt;मणिपुर के राज्यपाल अजय कुमार भल्ला&lt;/strong&gt; द्वारा &lt;strong data-end=&quot;320&quot; data-start=&quot;293&quot;&gt;दरबार हॉल, राजभवन&lt;/strong&gt;, इंफाल में प्रशासित की गई थी।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;427&quot; data-start=&quot;330&quot;&gt;
	&lt;p data-end=&quot;427&quot; data-start=&quot;332&quot;&gt;न्यायमूर्ति सुंदर ने &lt;strong data-end=&quot;387&quot; data-start=&quot;356&quot;&gt;न्यायमूर्ति केम्पैया सोमशेखर&lt;/strong&gt; का स्थान ग्रहण किया।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;502&quot; data-start=&quot;428&quot;&gt;
	&lt;p data-end=&quot;502&quot; data-start=&quot;430&quot;&gt;&lt;strong&gt;सर्वोच्च न्यायालय कॉलेजियम ने उन्हें&lt;/strong&gt; इस पद के लिए सिफारिश की थी।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;646&quot; data-start=&quot;503&quot;&gt;
	&lt;p data-end=&quot;646&quot; data-start=&quot;505&quot;&gt;&lt;strong data-end=&quot;524&quot; data-start=&quot;505&quot;&gt;चेन्नई में जन्मे&lt;/strong&gt; &lt;strong data-end=&quot;545&quot; data-start=&quot;528&quot;&gt;19 जुलाई, 1966&lt;/strong&gt; को, न्यायमूर्ति सुंदर ने &lt;strong data-end=&quot;599&quot; data-start=&quot;577&quot;&gt;मद्रास लॉ कॉलेज&lt;/strong&gt; से स्नातक किया और 1989 में एक अधिवक्ता के रूप में अपने करियर की शुरुआत की।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;806&quot; data-start=&quot;647&quot;&gt;
	&lt;p data-end=&quot;806&quot; data-start=&quot;649&quot;&gt;उन्हें &lt;strong data-end=&quot;689&quot; data-start=&quot;670&quot;&gt;स्थायी न्यायाधीश&lt;/strong&gt; के रूप में &lt;strong data-end=&quot;718&quot; data-start=&quot;697&quot;&gt;मद्रास उच्च न्यायालय&lt;/strong&gt; में &lt;strong data-end=&quot;738&quot; data-start=&quot;722&quot;&gt;अक्टूबर 2016&lt;/strong&gt; में पदोन्नत किया गया था और अपने स्थानांतरण से पहले &lt;strong data-end=&quot;785&quot; data-start=&quot;757&quot;&gt;दूसरे वरिष्ठतम न्यायाधीश&lt;/strong&gt; के रूप में कार्य किया।&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;
